-- ============================================================
-- Seed 500 Recruitment Interview Questions
-- Migration 062: Populate recruitment_questions table
-- ============================================================
-- Categories: Platform Features, Landlord Tools, Tenant Process,
-- Pricing & Fees, Legal & Compliance, Services (Transportation, Fumigation),
-- Technical Support, General Knowledge, Customer Service Scenarios,
-- Property Management
-- ============================================================

DO $$
DECLARE
  admin_id INTEGER;
  question_count INTEGER;
BEGIN
  -- Get a reference admin user (super_admin preferably)
  SELECT id INTO admin_id FROM users WHERE user_type = 'super_admin' LIMIT 1;
  
  -- Fallback if no super_admin exists
  IF admin_id IS NULL THEN
    SELECT id INTO admin_id FROM users ORDER BY id LIMIT 1;
  END IF;

  -- Check current count
  SELECT COUNT(*) INTO question_count FROM recruitment_questions WHERE is_active = TRUE;
  
  -- Seed whenever the active bank is below the required 500-question target.
  IF question_count < 500 THEN
    -- ============================================================
    -- PLATFORM FEATURES (50 questions)
    -- ============================================================

    -- ============================================================
    -- LANDLORD TOOLS (50 questions)
    -- ============================================================

    -- ============================================================
    -- TENANT PROCESS (50 questions)
    -- ============================================================

    -- ============================================================
    -- PRICING & FEES (50 questions)
    -- ============================================================

    -- ============================================================
    -- LEGAL & COMPLIANCE (50 questions)
    -- ============================================================

    -- ============================================================
    -- SERVICES - Transportation & Fumigation (50 questions)
    -- ============================================================

    -- ============================================================
    -- TECHNICAL SUPPORT (50 questions)
    -- ============================================================

    -- ============================================================
    -- GENERAL KNOWLEDGE (50 questions)
    -- ============================================================

    -- ============================================================
    -- CUSTOMER SERVICE SCENARIOS (50 questions)
    -- ============================================================

    -- ============================================================
    -- PROPERTY MANAGEMENT (50 questions)
    -- ============================================================
  END IF;
END $$;

